```class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        int count = 0;
        for (int i = 0; i < n; i++) {
            count += (delay + forget - i) % delay;
        }
        return count % (1000000007);
    }
};
```

